import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestClientBuilder;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.util.HashMap;
import java.util.Map;

@Configuration
public class ElasticsearchConfig {

    @Value("${elasticsearch.url}")
    private String elasticsearchUrl;

    @Bean
    public RestHighLevelClient restHighLevelClient() {
        RestClientBuilder builder = RestClient.builder(new URI(elasticsearchUrl));
        return new RestHighLevelClient(builder);
    }
}

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;

    @Autowired
    public ProductSearchService(RestHighLevelClient client) {
        this.client = client;
    }

    public void indexProduct(Product product) throws Exception {
        Map<String, Object> jsonMap = new HashMap<>();
        jsonMap.put("id", product.getId());
        jsonMap.put("name", product.getName());
        jsonMap.put("description", product.getDescription());

        IndexRequest request = new IndexRequest("products")
                .source(jsonMap);

        client.index(request, RequestOptions.DEFAULT);
    }

    public SearchResponse searchProducts(String query) throws Exception {
        GetRequest getRequest = new GetRequest("products")
                .setRouting(query);

        SearchResponse response = client.search(getRequest, RequestOptions.DEFAULT);

        return response;
    }
}

import org.elasticsearch.action.search.SearchResponse;
import org.springframework.beans.factory.annotation.Autowired;

@RestController
@RequestMapping("/api/search")
public class ProductSearchController {

    private final ProductSearchService productSearchService;

    @Autowired
    public ProductSearchController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping
    public SearchResponse search(@RequestBody String query) throws Exception {
        return productSearchService.searchProducts(query);
    }
}